// PURE ‚Äî same input, same output, no observable side effect
int doubled(int x) { return x * 2; }
String shout(String s) { return s.toUpperCase() + "!"; }

// IMPURE ‚Äî depends on shared state
private int seed = 0;
int nextId() { return ++seed; }              // different result each call

// IMPURE ‚Äî has a side effect
void saveOrder(Order o) { db.insert(o); }   // touches the database

// IMPURE ‚Äî reads external state
Instant now() { return Instant.now(); }     // clock changes

// Real apps have BOTH. The trick: push impurity to the edges.
// Keep the middle pure. Business logic that's pure = easy to test.

// BAD ‚Äî null-checks pyramid
User u = repo.findById(id);
if (u != null) {
  Address a = u.getAddress();
  if (a != null) {
    String c = a.getCity();
    if (c != null) {
      System.out.println(c);
    }
  }
}

// GOOD ‚Äî functional Optional chain
repo.findById(id)              // Optional<User>
    .map(User::getAddress)     // Optional<Address>  ‚Äî auto-flattens null
    .map(Address::getCity)     // Optional<String>
    .ifPresent(System.out::println);

// With a fallback
String city = repo.findById(id)
    .map(User::getAddress)
    .map(Address::getCity)
    .orElse("Unknown");

// A method that returns a function ‚Äî currying / partial application
Function<Integer, Integer> multiplyBy(int factor) {
  return x -> x * factor;
}
Function<Integer, Integer> triple = multiplyBy(3);
triple.apply(10);   // 30

// A method that takes a function
<T, R> List<R> mapAll(List<T> in, Function<T, R> fn) {
  return in.stream().map(fn).toList();
}
mapAll(List.of("a", "bb", "ccc"), String::length);   // [1, 2, 3]

// File: FunctionalDemo.java
// Run: javac FunctionalDemo.java && java FunctionalDemo
import java.util.*;
import java.util.function.*;
import java.util.stream.*;

record Product(String name, String category, double price, int stock) { }

public class FunctionalDemo {
  // Pure predicate
  static final Predicate<Product> inStock = p -> p.stock() > 0;
  static Predicate<Product> priceUnder(double max) {
    return p -> p.price() < max;
  }

  // Pure transformation
  static Function<Product, String> label = p -> p.name() + " ($" + p.price() + ")";

  public static void main(String[] args) {
    List<Product> catalog = List.of(
      new Product("Chair",  "furniture", 2000, 5),
      new Product("Sofa",   "furniture", 9000, 2),
      new Product("Lamp",   "lighting",   800, 0),
      new Product("Bulb",   "lighting",   200, 12),
      new Product("Table",  "furniture", 4000, 0),
      new Product("Cable",  "electric",   300, 20));

    // 1. Composition ‚Äî inStock AND priceUnder(1000)
    List<String> affordable = catalog.stream()
        .filter(inStock.and(priceUnder(1000)))
        .map(label)
        .toList();
    System.out.println("in stock, under 1000: " + affordable);

    // 2. Optional ‚Äî first product matching a predicate
    Optional<Product> firstFurniture = catalog.stream()
        .filter(p -> p.category().equals("furniture") && p.stock() > 0)
        .findFirst();
    firstFurniture
        .map(label)
        .ifPresentOrElse(
          s -> System.out.println("first furniture: " + s),
          () -> System.out.println("no furniture in stock"));

    // 3. Aggregation without mutation
    double totalValue = catalog.stream()
        .mapToDouble(p -> p.price() * p.stock())
        .sum();
    System.out.println("total inventory value: " + totalValue);

    // 4. Grouping ‚Äî pure, immutable Map returned
    Map<String, List<Product>> byCategory = catalog.stream()
        .collect(Collectors.groupingBy(Product::category));
    System.out.println("categories: " + byCategory.keySet());

    // 5. Curried price adjuster
    Function<Double, Function<Product, Double>> priceAfterTax = tax -> p -> p.price() * (1 + tax);
    Function<Product, Double> afterGst = priceAfterTax.apply(0.18);
    Function<Product, Double> afterCess = priceAfterTax.apply(0.28);
    System.out.println("chair after GST : " + afterGst.apply(catalog.get(0)));
    System.out.println("chair after cess: " + afterCess.apply(catalog.get(0)));
  }
}

// Expected output:
//   in stock, under 1000: [Bulb ($200.0), Cable ($300.0)]
//   first furniture: Chair ($2000.0)
//   total inventory value: 20800.0
//   categories: [furniture, lighting, electric]
//   chair after GST : 2360.0
//   chair after cess: 2560.0
